import { _decorator, Component, Node,SystemEvent, Event} from 'cc';
import { mEmitter } from './mEmitter';
import { EventType } from './Constants';
const { ccclass, property } = _decorator;

@ccclass('Control')
export class Control extends Component {
    protected onLoad(): void {
        new mEmitter();
        let systemEvent = new SystemEvent();
        systemEvent.on(SystemEvent.EventType.KEY_DOWN, this.onClickEnable.bind(this), this);
    }

    start() {

    }

    update(deltaTime: number) {

    }
    onClickEnable(event: Event) {
        mEmitter.instance.emit(EventType.ENABLE, 'holi');
        console.log(event)
    }

    onClickDisable() {
        mEmitter.instance.emit(EventType.DISABLE, 'hello');
        console.log("click disable")
    }

    onClickHoli(){
        mEmitter.instance.emit("HOLI");
        console.log("click holi")
    }

    clear(){
        this.node.destroy();
    }
}

